  @protected
  void sse_encode_shape_geometry(ShapeGeometry self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    switch (self) {
      case ShapeGeometry_Rectangle(
          width: final width,
          height: final height,
          r1: final r1,
          r2: final r2,
          r3: final r3,
          r4: final r4
        ):
        sse_encode_i_32(0, serializer);
        sse_encode_f_64(width, serializer);
        sse_encode_f_64(height, serializer);
        sse_encode_f_64(r1, serializer);
        sse_encode_f_64(r2, serializer);
        sse_encode_f_64(r3, serializer);
        sse_encode_f_64(r4, serializer);
      case ShapeGeometry_Ellipse(width: final width, height: final height):
        sse_encode_i_32(1, serializer);
        sse_encode_f_64(width, serializer);
        sse_encode_f_64(height, serializer);
      case ShapeGeometry_Text(
          width: final width,
          height: final height,
          text: final text,
          fontSize: final fontSize,
          fontFamily: final fontFamily,
          fontWeight: final fontWeight,
          lineHeight: final lineHeight,
          letterSpacingPercent: final letterSpacingPercent,
          textAlign: final textAlign
        ):
        sse_encode_i_32(2, serializer);
        sse_encode_f_64(width, serializer);
        sse_encode_f_64(height, serializer);
        sse_encode_String(text, serializer);
        sse_encode_f_64(fontSize, serializer);
        sse_encode_String(fontFamily, serializer);
        sse_encode_u_16(fontWeight, serializer);
        sse_encode_f_64(lineHeight, serializer);
        sse_encode_f_64(letterSpacingPercent, serializer);
        sse_encode_text_align(textAlign, serializer);
      case ShapeGeometry_Frame(
          width: final width,
          height: final height,
          clipContent: final clipContent
        ):
        sse_encode_i_32(3, serializer);
        sse_encode_f_64(width, serializer);
        sse_encode_f_64(height, serializer);
        sse_encode_bool(clipContent, serializer);
      case ShapeGeometry_Group(width: final width, height: final height):
        sse_encode_i_32(4, serializer);
        sse_encode_f_64(width, serializer);
        sse_encode_f_64(height, serializer);
      case ShapeGeometry_Path(
          width: final width,
          height: final height,
          pathData: final pathData,
          closed: final closed
        ):
        sse_encode_i_32(5, serializer);
        sse_encode_f_64(width, serializer);
        sse_encode_f_64(height, serializer);
        sse_encode_String(pathData, serializer);
        sse_encode_bool(closed, serializer);
      case ShapeGeometry_Image(
          width: final width,
          height: final height,
          assetId: final assetId
        ):
        sse_encode_i_32(6, serializer);
        sse_encode_f_64(width, serializer);
        sse_encode_f_64(height, serializer);
        sse_encode_String(assetId, serializer);
      case ShapeGeometry_Svg(
          width: final width,
          height: final height,
          svgContent: final svgContent
        ):
        sse_encode_i_32(7, serializer);
        sse_encode_f_64(width, serializer);
        sse_encode_f_64(height, serializer);
        sse_encode_String(svgContent, serializer);
      case ShapeGeometry_Bool(
          width: final width,
          height: final height,
          operation: final operation
        ):
        sse_encode_i_32(8, serializer);
        sse_encode_f_64(width, serializer);
        sse_encode_f_64(height, serializer);
        sse_encode_bool_op(operation, serializer);
    }
  }

  @protected
  void sse_encode_shape_gradient(ShapeGradient self, SseSerializer serializer) {
    // Codec=Sse (Serialization based), see doc to use other codecs
    sse_encode_gradient_type(self.gradientType, serializer);
